"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[36914],{39143:(e,i,n)=>{n.r(i),n.d(i,{data:()=>r});const r={key:"v-e930821a",path:"/C#/%E8%87%AA%E5%AE%9A%E4%B9%89%E6%8E%A7%E4%BB%B6/06.CompositeControl%E7%9A%84%E5%91%88%E7%8E%B0.html",title:"自定义控件(六)-CompositeControl的呈现",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"C#/自定义控件/06.CompositeControl的呈现.md"}},26038:(e,i,n)=>{n.r(i),n.d(i,{default:()=>s});const r=(0,n(57293).uE)('<h1 id="自定义控件-六-compositecontrol的呈现" tabindex="-1"><a class="header-anchor" href="#自定义控件-六-compositecontrol的呈现" aria-hidden="true">#</a> 自定义控件(六)-CompositeControl的呈现</h1><p>在现实开发中，我们往往不需要从零开始构建自定义控件，更多时候我们是把多个已有的控件组织起来，组成一个新的控件，如Login控件,Wizard控件。</p><p>下面演示一个LinkButton+Image=ImageButton的示例</p><p>代码</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>using System.Web.UI;\nusing System.Web.UI.WebControls;\n\nnamespace kjlx.BLL.CompositeControlTest\n{\n    public class ImageButton:CompositeControl\n    {\n        private LinkButton lb;\n        private Image img;\n        protected override HtmlTextWriterTag TagKey\n        {\n            get { return HtmlTextWriterTag.Div; }\n        }\n        //创建子控件\n        protected override void CreateChildControls()\n        {\n            Controls.Clear();                                 //把CompositeConrol的Controls集合(从Control继承)清空       \n            img=new Image();                                  //实例化image\n            img.ImageUrl = &quot;images/Nature.jpg&quot;;               //设置图片地址\n            lb=new LinkButton();                              //实例化LinkButton\n            lb.PostBackUrl = &quot;http://www.baidu.com&quot;;          //设置超链接\n            lb.Controls.Add(img);                             //把img添加到LinkButton中\n            this.Controls.Add(lb);                            //把LinkButton添加到Div中\n            ChildControlsCreated = true;                      //避免重复调用CreateChildControls()方法\n        }\n\n    }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>显示结果</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210854477.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210854468.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>CompositeControl没有对基类(WebControl)的呈现逻辑进行更改,而仅仅是重写了Controls属性,增加了对EnsureChildControls()方法的调用,EnsureChildControls()方法会判断ChildControlsCreated属性的值，如果不为True,则会调用CreateChildControls()方法创建子控件。此外,我们在CreateChildControls()方法的最后把ChildControlsCreated设为true,这样既保证组合控件的子控件得以创建，又不会重复调用创建子控件的过程。</p><p>下面通过一个例子展示CompositeControl是如何定义子控件的：</p><p>代码</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>using System.IO;\nusing System.Web.UI;\nusing System.Web.UI.WebControls;\n\n\nnamespace kjlx.BLL.CompositeControlTest\n{\n    public class ImageButton1:CompositeControl\n    {\n        private LinkButton lb;\n        private Image img;\n        static StringWriter sw=new StringWriter();\n        private HtmlTextWriter writer2 = new HtmlTextWriter(sw);\n        protected override HtmlTextWriterTag TagKey\n        {\n            get { return HtmlTextWriterTag.Div; }\n        }\n        public override void RenderBeginTag(HtmlTextWriter writer)\n        {\n            writer2.WriteLine(&quot;调用了RenderBeginTag&lt;/br&gt;&quot;);\n            base.RenderBeginTag(writer);\n        }\n        protected override void RenderContents(HtmlTextWriter writer)\n        {\n            writer2.WriteLine(&quot;调用了RenderContents&lt;/br&gt;&quot;);\n            base.RenderContents(writer);\n        }\n        protected override void Render(HtmlTextWriter writer)\n        {\n            writer2.WriteLine(&quot;调用了Render&lt;/br&gt;&quot;);\n            base.Render(writer);\n        } \n        //创建子控件\n        protected override void CreateChildControls()\n        {\n            writer2.WriteLine(&quot;调用了CreateChildControls&lt;/br&gt;&quot;);\n            Controls.Clear();                                 //把CompositeConrol的Controls集合(从Control继承)清空       \n            img=new Image();                                  //实例化image\n            img.ImageUrl = &quot;images/Nature.jpg&quot;;               //设置图片地址\n            lb=new LinkButton();                              //实例化LinkButton\n            lb.PostBackUrl = &quot;http://www.baidu.com&quot;;          //设置超链接\n            lb.Controls.Add(img);                             //把img添加到LinkButton中\n            this.Controls.Add(lb);                            //把LinkButton添加到Div中\n            ChildControlsCreated = true;                      //避免重复调用CreateChildControls()方法\n        }\n        protected override void EnsureChildControls()\n        {\n            writer2.WriteLine(&quot;调用了EnsureChildControls&lt;/br&gt;&quot;);\n            base.EnsureChildControls();\n        }\n\n\n        protected override void RenderChildren(HtmlTextWriter writer)\n        {\n            writer2.WriteLine(&quot;调用了RenderChildren&lt;/br&gt;&quot;);\n            \n            base.RenderChildren(writer);\n           \n        }\n        public override void RenderEndTag(HtmlTextWriter writer)\n        {\n            writer2.WriteLine(&quot;调用了RenderEndTag&lt;/br&gt;&quot;);\n            base.RenderEndTag(writer);\n            writer.Write(sw.ToString());\n        }\n    }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>显示结果</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210854437.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>从显示结果中我们可以知道，CompositeControl函数的执行顺序</p><p>1.EnsureChildControls() //判断ChildControlsCreate属性的值</p><p>2.CreateChildControls() //创建子控件,并添加到Controls中</p><p>3.EnsureChildControl() //判断子控件是否初始化，执行次数为添加到Controls中的控件数，子控件的子控件也算，如img</p><p>4.Render()</p><p>5.RenderBeginTag() //添加开始标签</p><p>6.RenderContents() //添加内容</p><p>7.RenderChildren() //添加子控件</p><p>8.RenderEndTag() //添加结束标签</p>',25),l={},s=(0,n(63243).Z)(l,[["render",function(e,i){return r}]])},63243:(e,i)=>{i.Z=(e,i)=>{const n=e.__vccOpts||e;for(const[e,r]of i)n[e]=r;return n}}}]);